    @Override // com.genoma.plus.dao.laboratorio.LaboratorioBienestarDAO
    public Long addResultado(final String idRecepcion, final String fechaResult, final String observacion, final Long idProfesional, final Long idEspecialidad, final String soporte, final String url) {
        GeneratedKeyHolder generatedKeyHolder = new GeneratedKeyHolder();
        this.jdbcTemplate.update(new PreparedStatementCreator() { // from class: com.genoma.plus.dao.impl.laboratorio.LaboratorioBienestarDAOImpl.6
            public PreparedStatement createPreparedStatement(Connection connection) throws SQLException {
                PreparedStatement ps = connection.prepareStatement("INSERT INTO l_resultados(Id_Recepcion, FechaResult, Observacion, Id_Profesional, Id_Especialidad, Soporte, Url, fecha, UsuarioS)     VALUES (?,?,?,?,?,?,?,?,?)", 1);
                ps.setString(1, idRecepcion);
                ps.setString(2, fechaResult);
                ps.setString(3, observacion);
                ps.setLong(4, idProfesional.longValue());
                ps.setLong(5, idEspecialidad.longValue());
                ps.setString(6, soporte);
                ps.setString(7, url);
                ps.setString(8, LaboratorioBienestarDAOImpl.this.xmt.formatoAMDH24.format(LaboratorioBienestarDAOImpl.this.xmt.getFechaActual()));
                ps.setString(9, Principal.usuarioSistemaDTO.getLogin());
                return ps;
            }
        }, generatedKeyHolder);
        return Long.valueOf(generatedKeyHolder.getKey().longValue());
    }

