        String xsql = sexo.equals("F") ? "SELECT l_tiporesultado.Id, l_tiporesultado.Nbre, l_tiporesultado.Vandera, `l_protocoloxtiporesultado`.Alterado , l_protocolos.VrMinF, l_protocolos.VrMaxF " : "SELECT l_tiporesultado.Id, l_tiporesultado.Nbre, l_tiporesultado.Vandera, `l_protocoloxtiporesultado`.Alterado , l_protocolos.VrMinM, l_protocolos.VrMaxM ";
