    @Override // com.genoma.plus.dao.laboratorio.LaboratorioBienestarDAO
    public void updateDatelleResultadoEnviado(int idRecepcion) {
        this.jdbcTemplate.update("update l_detalleresultado,(\nSELECT         `l_recepcion`.`Id`\n\t\t\t    , CONCAT(`ingreso`.`NoAutorizacion`) AS `OrdenConsecutivo`\n\t\t\t    , `g_persona`.`Id_TipoIdentificacion` AS `PacienteTipoDocumento`\n\t\t\t    , `g_persona`.`NoDocumento` AS `PacienteIdentificacion`\n\t\t\t    , `l_detalleresultado`.`Id_Procedimiento` AS `CodigoExamen`\n\t\t\t    , `f_itemordenesproced`.`NAutorizacion` AS `DetalleOrdenOid`\n\t\t\t    , DATE_FORMAT(`l_detalleresultado`.`Fecha`, '%Y-%m-%d') AS `FechaValidacion`\n\t\t\t    , DATE_FORMAT(`l_detalleresultado`.`Fecha`, '%H:%i') AS `HoraValidacion`\n\t\t\t    , `l_resultados`.`Observacion` AS `Observacion`\n\t\t\t    , `profesional`.`Id` AS `UsuarioValidaID`\n\t\t\t    , CONCAT(`profesional`.`Nombre1` ,' ', `profesional`.`Nombre2`,' ',`profesional`.`Apellido1`,' ',`profesional`.`Apellido2`) AS `UsuarioValidaNombre`\n\t\t\t    , 'LABORATORIO HOSPITAL' AS `LaboratorioNombre`\n\t\t\t    , `l_protocolos`.`Id` AS `AnalitoCodigo`\n\t\t\t    , `l_protocolos`.`Nbre` AS `AnalitoNombre`\n\t\t\t    , `l_detalleresultado`.`VrNumerico` AS `Resultado`\n\t\t\t    , `l_detalleresultado`.`Unidad` AS `UnidadMedida`\n\t\t\t    , `l_detalleresultado`.`VReferencia1` AS `Minimo`\n\t\t\t    , `l_detalleresultado`.`VReferencia2` AS `Maximo`\n\t\t\t    , `l_protocoloxprocedimiento`.`Orden`\n\t\t\t    ,l_detalleresultado.Id_Resultado\n\t\t\t    ,l_detalleresultado.Id_Procedimiento\n\t\t\t    ,l_detalleresultado.Id_ProtocolProcedim\n\t\t\tFROM\n\t\t\t    `l_detallerecepcion`\n\t\t\t    INNER JOIN `l_recepcion` \n\t\t\t        ON (`l_detallerecepcion`.`Id_Recepcion` = `l_recepcion`.`Id`)\n\t\t\t    INNER JOIN `l_resultados` \n\t\t\t        ON (`l_resultados`.`Id_Recepcion` = `l_recepcion`.`Id`)\n\t\t\t    INNER JOIN `f_ordenes` \n\t\t\t        ON (`l_recepcion`.`Id_OrdenFacturac` = `f_ordenes`.`Id`)\n\t\t\t    INNER JOIN `l_detalleresultado` \n\t\t\t        ON (`l_detalleresultado`.`Id_Procedimiento` = `l_detallerecepcion`.`Id_Procedim`) AND (`l_detalleresultado`.`Id_Resultado` = `l_resultados`.`Id`)\n\t\t\t    INNER JOIN `l_protocoloxprocedimiento` \n\t\t\t        ON (`l_detalleresultado`.`Id_ProtocolProcedim` = `l_protocoloxprocedimiento`.`Id`)\n\t\t\t    INNER JOIN `l_protocolos` \n\t\t\t        ON (`l_protocoloxprocedimiento`.`Id_Protocolo` = `l_protocolos`.`Id`)\n\t\t\t    INNER JOIN `ingreso` \n\t\t\t        ON (`f_ordenes`.`Id_Ingreso` = `ingreso`.`Id`)\n\t\t\t    INNER JOIN `g_usuario` \n\t\t\t        ON (`ingreso`.`Id_Usuario` = `g_usuario`.`Id_persona`)\n\t\t\t    INNER JOIN `f_itemordenesproced` \n\t\t\t        ON (`f_itemordenesproced`.`Id_Procedimiento` = `l_detallerecepcion`.`Id_Procedim`) AND (`f_itemordenesproced`.`Id_Ordenes` = `f_ordenes`.`Id`)\n\t\t\t    INNER JOIN `g_persona` \n\t\t\t        ON (`g_usuario`.`Id_persona` = `g_persona`.`Id`)\n\t\t\t    INNER JOIN `g_persona` AS `profesional` \n\t\t\t        ON (`profesional`.`Id` = `l_detalleresultado`.`Bacteriologo`)\n\t\t\tWHERE (`l_recepcion`.`Id` =? and l_detalleresultado.Enviado=0\n\t\t\t    AND `l_detalleresultado`.`Estado` =1)\n\t\t\tORDER BY `l_detalleresultado`.`Id_Procedimiento` ASC, `l_protocoloxprocedimiento`.`Orden` ASC) tmp\nset l_detalleresultado.Enviado=1\nwhere l_detalleresultado.Id_Resultado=tmp.Id_Resultado and\nl_detalleresultado.Id_Procedimiento=tmp.Id_Procedimiento and\nl_detalleresultado.Id_ProtocolProcedim=tmp.Id_ProtocolProcedim", new Object[]{Integer.valueOf(idRecepcion)});
    }

