    public List<Object[]> listaResultadosExportacionInstitucional(String fechaI, String fechaF, String idEmpresa, String filtro) {
        RowMapper mapper = new RowMapper() { // from class: com.genoma.plus.dao.impl.laboratorio.LaboratorioBienestarDAOImpl.39
            public Object mapRow(ResultSet rs, int rowNum) throws SQLException {
                Object[] fila = {rs.getString("FechaRP"), rs.getString("IdRecepcion"), rs.getString("NoDocumento"), rs.getString("NUsuario"), rs.getString("codigoExtero"), rs.getString("CodigoProcedimiento"), rs.getString("NbreProcedimiento"), rs.getString("NbreProtocolo"), rs.getString("VrNumerico"), rs.getString("FechaResultado"), rs.getString("VReferencia1"), rs.getString("VReferencia2"), rs.getString("NoAutorizacion"), rs.getString("Id_persona"), rs.getString("LoteProcedimiento")};
                return fila;
            }
        };
        String sql = "SELECT\n\tDATE_FORMAT(FechaRecep, '%Y%m%d') AS FechaRP,\n\tl_recepcion.Id AS IdRecepcion,\n\tpersona.NoDocumento,\n\tpersona.NUsuario,\n\tg_procedimiento.Id AS CodigoProcedimiento,\t\n\tl_protocoloprocedimiento_empresa.codigoExtero,\n\tg_procedimiento.Nbre AS NbreProcedimiento,\n\tl_protocolos.Nbre AS NbreProtocolo,\t\t \n\tl_detalleresultado.VrNumerico,\n\tDATE_FORMAT(l_detalleresultado.Fecha,'%d/%m/%Y %h:%i:%s %p') AS FechaResultado,\n\tif(LENGTH(l_detalleresultado.VReferencia1)=0 or l_detalleresultado.VReferencia1 is null, ' ',l_detalleresultado.VReferencia1) AS VReferencia1,\n\tif(LENGTH(l_detalleresultado.VReferencia2)=0 or l_detalleresultado.VReferencia2 is null, ' ',l_detalleresultado.VReferencia2) AS VReferencia2,\n\tl_recepcion.Id_OrdenFacturac, \n\tpersona.Id_persona, \n     d.LoteProcedimiento,\n     ingreso.NoAutorizacion\nFROM\n\tl_detallerecepcion\nINNER JOIN baseserver.l_recepcion ON\n\t(l_detallerecepcion.Id_Recepcion = l_recepcion.Id)\nINNER JOIN persona ON \n    (l_recepcion.Id_Paciente = persona.Id_persona)\nINNER JOIN l_resultados ON\n\t(l_resultados.Id_Recepcion = l_recepcion.Id)\nINNER JOIN baseserver.l_detalleresultado ON\n\t(l_detalleresultado.Id_Resultado = l_resultados.Id)\nINNER JOIN baseserver.g_procedimiento ON\n\t(l_detallerecepcion.Id_Procedim = g_procedimiento.Id)\nINNER JOIN l_protocoloxprocedimiento ON\n\t(l_protocoloxprocedimiento.Id_Procedim = g_procedimiento.Id)\n\tAND (l_detalleresultado.Id_ProtocolProcedim = l_protocoloxprocedimiento.Id)\nINNER JOIN l_protocolos ON\n\t(l_protocoloxprocedimiento.Id_Protocolo =l_protocolos.Id )\nINNER JOIN l_protocoloprocedimiento_empresa ON\n\t(l_protocoloprocedimiento_empresa.idProtocoloProcedi = l_detalleresultado.Id_ProtocolProcedim )\n\t AND (l_protocoloprocedimiento_empresa.idEmpresa=" + idEmpresa + ")\nLEFT JOIN (SELECT GROUP_CONCAT(l_detallerecepcion.`Id_Procedim` SEPARATOR ',') AS LoteProcedimiento, l_detallerecepcion.Id_Recepcion FROM l_detallerecepcion GROUP BY l_detallerecepcion.Id_Recepcion) d ON (d.Id_Recepcion= l_recepcion.Id )\nINNER JOIN `f_empresacontxconvenio` ON\n\t(`l_recepcion`.`Id_EmpresaConv`= `f_empresacontxconvenio`.`Id`)\nINNER JOIN f_ordenes ON\n     (f_ordenes.Id = l_recepcion.Id_OrdenFacturac)\nINNER JOIN ingreso ON\n     (ingreso.Id = f_ordenes.Id_Ingreso)\nWHERE\n\t(DATE_FORMAT(l_recepcion.FechaRecep, '%Y-%m-%d') >='" + fechaI + "'\n\tAND DATE_FORMAT(l_recepcion.FechaRecep, '%Y-%m-%d') <='" + fechaF + "'\n\tAND l_detallerecepcion.validadolab = 1\n\tAND `l_recepcion`.`Estado`=0\n     AND f_empresacontxconvenio.Id_EmpresaCont=" + idEmpresa + "\n     AND ingreso.NoAutorizacion <>''\n\tAND (`persona`.`NUsuario` LIKE '%" + filtro + "%' OR `persona`.`NoDocumento` LIKE '%" + filtro + "%')\n\t)\nGROUP BY\n\tl_recepcion.Id,\n\tg_procedimiento.Nbre,\n\tl_protocolos.`Id`\nORDER BY\n\tFechaResult DESC,\n\tl_recepcion.Id ASC";
        List<Object[]> list = this.jdbcTemplate.query(sql, mapper);
        return list;
    }

